// Parse and validate incoming webhook data
const inputData = $input.first()?.json || {};

const runData = inputData.run || inputData;
const modelData = inputData.model || {};
const recipientData = inputData.recipients || {};

return {
  json: {
    run_id: runData.id,
    run_type: runData.run_type || 'benchmark',
    status: runData.status || 'completed',
    status_message: runData.status_message || '',
    build_name: runData.build_name || '',
    model_id: modelData.id || runData.model_id,
    model_name: modelData.name || 'Unknown Model',
    model_checkpoint: modelData.checkpoint || '',
    started_at: runData.started_at,
    completed_at: runData.completed_at,
    duration_seconds: runData.duration_seconds,
    device: runData.device || '',
    backend: runData.backend || '',
    // Recipients
    email_recipients: recipientData.email || [],
    slack_channels: recipientData.slack || [],
    teams_channels: recipientData.teams || [],
    // Dashboard URL
    dashboard_url: $env.DASHBOARD_FRONTEND_URL || 'http://localhost:3000',
    run_url: `${$env.DASHBOARD_FRONTEND_URL || 'http://localhost:3000'}/runs/${runData.id}`,
    // Timestamp
    notification_time: new Date().toISOString()
  }
};

