// Aggregate notification results
const emailResult = $node["Send Email"]?.json;
const slackResult = $node["Send Slack"]?.json;
const teamsResult = $node["Send Teams"]?.json;

return {
  json: {
    notification_summary: {
      run_id: $input.first().json.run_id,
      model_name: $input.first().json.model_name,
      status: $input.first().json.status,
      email_sent: emailResult ? true : false,
      slack_sent: slackResult ? true : false,
      teams_sent: teamsResult ? true : false,
      timestamp: new Date().toISOString()
    }
  }
};

